-- ----------------------------
-- Table structure for mdc_msg_task
-- ----------------------------
DROP TABLE IF EXISTS `mdc_msg_task`;
CREATE TABLE `mdc_msg_task` (
  `id` bigint NOT NULL COMMENT 'ID',
  `template_id` bigint DEFAULT NULL COMMENT '消息模板',
  `type` smallint NOT NULL DEFAULT '1' COMMENT '消息类型\n[1-站内信 2-短信 3-邮件]',
  `status` smallint NOT NULL DEFAULT '0' COMMENT '执行状态\n[0-草稿 1-待执行 2-执行成功 3-执行失败]',
  `channel` smallint NOT NULL COMMENT '发送渠道\n[1-后台发送 2-API发送 3-JOB发送]',
  `msg_category` smallint DEFAULT NULL COMMENT '消息分类\n[1-待办 2-预警 3-提醒]',
  `recipient_scope` smallint NOT NULL DEFAULT '1' COMMENT '接收范围\n[0-所有人 1-指定用户 2-指定角色 3-指定部门]',
  `param` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '参数\n需要封装为[{‘key’:‘‘,;’value’:‘‘}, {’key2’:‘‘, ’value2’:‘‘}]格式',
  `title` varchar(255) DEFAULT NULL COMMENT '标题',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '发送内容',
  `url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '跳转地址',
  `is_timing` bit(1) DEFAULT b'0' COMMENT '是否定时发送',
  `scheduled_send_time` datetime(3) DEFAULT NULL COMMENT '计划发送时间',
  `send_time` datetime(3) DEFAULT NULL COMMENT '发送时间',
  `biz_id` bigint DEFAULT NULL COMMENT '业务ID\nApi发送和job发送时指定，用于业务追踪',
  `biz_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '业务类型\nApi发送和job发送时指定，用于业务追踪',
  `author` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '发送人',
  `sender_id` bigint DEFAULT NULL COMMENT '发送人ID',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '最后修改人',
  `updated_at` datetime(3) DEFAULT NULL COMMENT '最后修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `tempate_id_topic_content` (`template_id`,`title`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='消息任务';

