-- ----------------------------
-- Table structure for mdc_msg_template
-- ----------------------------
DROP TABLE IF EXISTS `mdc_msg_template`;
CREATE TABLE `mdc_msg_template` (
  `id` bigint NOT NULL COMMENT '模板ID',
  `interface_config_id` bigint NOT NULL COMMENT '接口ID',
  `msg_type` smallint NOT NULL DEFAULT '1' COMMENT '消息类型\n[1-站内信 2-短信 3-邮件 ]',
  `key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '模板标识',
  `name` varchar(255) DEFAULT NULL COMMENT '模板名称',
  `state` bit(1) DEFAULT b'1' COMMENT '状态',
  `sms_template_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '模板编码\n第三方模板编码（如，消息类型为短信时，第三方短信商的模版id）',
  `sms_sign` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '签名',
  `title` varchar(255) DEFAULT NULL COMMENT '标题',
  `content` longtext NOT NULL COMMENT '模板内容',
  `script` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '脚本',
  `param` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '标题参数',
  `remarks` varchar(255) DEFAULT NULL COMMENT '备注',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '最后修改人',
  `updated_at` datetime(3) DEFAULT NULL COMMENT '最后修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `UK_MSG_TEMPLATE_CODE` (`key`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='消息模板';

-- ----------------------------
-- Records of mdc_msg_template
-- ----------------------------
BEGIN;
