-- ----------------------------
-- Table structure for mdc_resource_menu
-- ----------------------------
DROP TABLE IF EXISTS `mdc_resource_menu`;
CREATE TABLE `mdc_resource_menu` (
  `id` bigint NOT NULL COMMENT 'ID',
  `app_id` bigint NOT NULL COMMENT '所属应用',
  `code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '编码',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '名称',
  `menu_type` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '20' COMMENT '类型\n[10-目录  20-菜单 30-内链 40-外链]',
  `remarks` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '备注',
  `path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '路由地址',
  `component` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '页面地址',
  `redirect` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '' COMMENT '重定向',
  `state` bit(1) NOT NULL DEFAULT b'1' COMMENT '状态\n[0-禁用 1-启用]',
  `tree_path` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '/' COMMENT '树路径',
  `parent_id` bigint DEFAULT NULL COMMENT '父级ID',
  `weight` int DEFAULT '1' COMMENT '顺序号',
  `meta` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '{}' COMMENT '元数据\n',
  `created_by` bigint DEFAULT NULL COMMENT '创建人id',
  `created_at` datetime(3) NOT NULL COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人id',
  `updated_at` datetime(3) NOT NULL COMMENT '更新时间',
  `deleted_by` bigint DEFAULT NULL COMMENT '删除人',
  `deleted_at` bigint NOT NULL DEFAULT '0' COMMENT '删除标志',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_resource_code` (`code`) USING BTREE,
  KEY `idx_app_type_sate_weight` (`app_id`,`menu_type`,`state`,`weight`) USING BTREE COMMENT '查询用户可用资源'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='菜单';

