-- ----------------------------
-- Table structure for mdo_api_call_log
-- ----------------------------
DROP TABLE IF EXISTS `mdo_api_call_log`;
CREATE TABLE `mdo_api_call_log` (
  `id` bigint NOT NULL COMMENT 'ID',
  `trace_id` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '调用链id',
  `app_id` bigint NOT NULL COMMENT '所属应用',
  `app_key` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '应用秘钥',
  `app_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '应用名称',
  `request_ip` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '请求IP',
  `api_id` bigint NOT NULL COMMENT '所属接口',
  `api_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '接口名称',
  `api_version` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '版本号',
  `interface_class_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '接口类名',
  `method_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '方法名称',
  `param_info` longtext COLLATE utf8mb4_general_ci COMMENT '请求参数',
  `request_header` text COLLATE utf8mb4_general_ci COMMENT '请求头',
  `request_time` datetime(3) DEFAULT NULL COMMENT '请求时间',
  `exec_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '执行状态\n[1-执行成功,2-执行失败]',
  `response_data` longtext COLLATE utf8mb4_general_ci COMMENT '响应内容',
  `response_time` datetime(3) DEFAULT NULL COMMENT '响应时间',
  `error_msg` longtext COLLATE utf8mb4_general_ci COMMENT '异常消息',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='调用日志';

-- ----------------------------
-- Records of mdo_api_call_log
-- ----------------------------
