-- ----------------------------
-- Table structure for mdo_app
-- ----------------------------
DROP TABLE IF EXISTS `mdo_app`;
CREATE TABLE `mdo_app` (
  `id` bigint NOT NULL COMMENT 'ID',
  `app_key` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '应用ID',
  `app_secret` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '应用秘钥',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '应用名称',
  `login_type` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '10' COMMENT '登录方式\n[10-单点登录 20-oauth2]',
  `type` char(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '10' COMMENT '应用类型\n[10-自建应用 20-第三方应用]',
  `state` bit(1) NOT NULL DEFAULT b'1' COMMENT '状态',
  `weight` int DEFAULT '0' COMMENT '权重',
  `intro` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '应用简介',
  `logo` bigint DEFAULT NULL COMMENT '应用图标',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `validity_start` datetime(3) DEFAULT NULL COMMENT '开始有效期',
  `validity_end` datetime(3) DEFAULT NULL COMMENT '结束有效期',
  `home_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '首页地址',
  `show` bit(1) NOT NULL DEFAULT b'1' COMMENT '是否显示\n是否在我的应用显示该应用，若设置为false，就算有权限访问，该应用也不会出现在我的应用列表',
  `is_public` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否公开\n[true=公开应用 false-私有应用]',
  `allow_ip` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '允许的IP',
  `sso_auto_login_url` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '单点登录自动登录地址',
  `sso_push` bit(1) NOT NULL DEFAULT b'1' COMMENT '是否接收消息推送',
  `sso_slo` bit(1) NOT NULL DEFAULT b'1' COMMENT '是否接收单点注销推送',
  `sso_push_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '接收消息推送的地址',
  `sso_allow_url` varchar(5120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '允许授权的URL\n多个用逗号分割',
  `oauth2_allow_redirect_uris` varchar(5120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '允许的重定向uri',
  `oauth2_allow_grant_types` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '允许的授权类型',
  `oauth2_new_refresh` int DEFAULT '-1' COMMENT 'Refresh-Token刷新策略\r\n[0-否 1-是 -1-全局配置]',
  `oauth2_access_token_timeout` bigint DEFAULT '-1' COMMENT 'access-token有效期\r\n单位：秒\r\n[-1-全局]',
  `oauth2_refresh_token_timeout` bigint DEFAULT '-1' COMMENT 'refresh-token有效期\n单位：秒\n[-1-全局]',
  `oauth2_client_token_timeout` bigint DEFAULT '-1' COMMENT 'client-token有效期\n单位：秒\n[-1-全局]',
  `oauth2_lower_client_token_timeout` bigint DEFAULT '-1' COMMENT 'lower-client-token有效期\n单位：秒\n[-1-全局]',
  `oauth2_is_confirm` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否自动授权\r\n[1-是 0-否]',
  `apply_id` bigint DEFAULT NULL COMMENT '应用申请ID',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  `updated_by` bigint DEFAULT NULL COMMENT '最后修改人',
  `updated_at` datetime(3) DEFAULT NULL COMMENT '最后修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_app_key` (`app_key`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='应用';

