-- ----------------------------
-- Table structure for mdo_app_keys
-- ----------------------------
DROP TABLE IF EXISTS `mdo_app_keys`;
CREATE TABLE `mdo_app_keys` (
  `id` bigint NOT NULL COMMENT 'id',
  `app_id` bigint NOT NULL DEFAULT '0' COMMENT '所属应用',
  `key_format` smallint NOT NULL DEFAULT '1' COMMENT '秘钥格式\r\n[1-PKCS8(JAVA适用) 2-PKCS1(非JAVA适用)]',
  `notify_url` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '通知地址',
  `notify_state` bit(1) DEFAULT b'0' COMMENT '通知状态',
  `notify_encryption_type` smallint DEFAULT NULL COMMENT '加密类型\n[0-不加密 1-aes加密 2-sm4加密]',
  `public_key_app` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '应用公钥\r\n平台方用来校验开发者推送过来的数据',
  `private_key_app` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '应用私钥\r\n一般由开发者自行生成或平台协助生成\r\n用来开发者签名推送给平台的数据',
  `public_key_platform` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '平台公钥\r\n提供给开发者，用来校验平台推送给开发者的数据签名是否正确',
  `private_key_platform` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '平台私钥\r\n平台使用，用来签名推送给开发者的数据',
  `created_at` datetime(3) DEFAULT CURRENT_TIMESTAMP(3) COMMENT '添加时间',
  `updated_at` datetime(3) DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3) COMMENT '修改时间',
  `created_by` bigint DEFAULT '0' COMMENT '创建人id',
  `updated_by` bigint DEFAULT '0' COMMENT '修改人id',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_appid` (`app_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='应用秘钥';

