INSERT INTO `mdo_app_keys` (`id`, `app_id`, `key_format`, `notify_url`, `notify_state`, `notify_encryption_type`, `public_key_app`, `private_key_app`, `public_key_platform`, `private_key_platform`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES (27094573554165765, 27094573554165761, 1, NULL, b'0', NULL, '', '', '', '', '2025-11-27 00:41:40.231', '2025-11-27 00:41:40.231', 680083598598475778, 680083598598475778);
