-- ----------------------------
-- Table structure for mdo_event_push
-- ----------------------------
DROP TABLE IF EXISTS `mdo_event_push`;
CREATE TABLE `mdo_event_push` (
  `id` bigint NOT NULL COMMENT 'ID',
  `event_trigger_id` bigint NOT NULL COMMENT '事件触发ID',
  `event_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '事件类型',
  `app_id` bigint NOT NULL COMMENT '所属应用',
  `app_key` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '应用秘钥',
  `notify_url` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '回调url',
  `request_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '请求参数',
  `last_request_time` datetime(3) DEFAULT NULL COMMENT '最后请求时间',
  `next_request_time` datetime(3) DEFAULT NULL COMMENT '下次请求时间',
  `max_request_cnt` int DEFAULT NULL COMMENT '最大请求次数',
  `request_cnt` int DEFAULT '0' COMMENT '已请求次数',
  `exec_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '执行状态\n[0-待执行 1-执行成功 2-执行失败 3-重试结束 4-手动结束]',
  `remark` varchar(256) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `created_at` datetime(3) DEFAULT CURRENT_TIMESTAMP(3) COMMENT '创建时间',
  `updated_at` datetime(3) DEFAULT CURRENT_TIMESTAMP(3) COMMENT '修改时间',
  `created_by` bigint DEFAULT '0' COMMENT '创建人id',
  `updated_by` bigint DEFAULT '0' COMMENT '修改人id',
  PRIMARY KEY (`id`),
  KEY `idx_app_key` (`app_key`),
  KEY `idx_event_trigger_id` (`event_trigger_id`,`app_id`,`exec_status`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='事件推送任务';

