-- ----------------------------
-- Table structure for mdo_event_subscription
-- ----------------------------
DROP TABLE IF EXISTS `mdo_event_subscription`;
CREATE TABLE `mdo_event_subscription` (
  `id` bigint NOT NULL COMMENT '主键',
  `app_id` bigint NOT NULL COMMENT '所属应用',
  `event_type_id` bigint NOT NULL COMMENT '所属事件',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_app_event` (`app_id`,`event_type_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='事件订阅';

