-- ----------------------------
-- Table structure for mdo_event_trigger
-- ----------------------------
DROP TABLE IF EXISTS `mdo_event_trigger`;
CREATE TABLE `mdo_event_trigger` (
  `id` bigint NOT NULL COMMENT 'ID',
  `event_code` varchar(255) COLLATE utf8mb4_general_ci NOT NULL COMMENT '事件编码',
  `event_id` bigint NOT NULL COMMENT '事件ID',
  `trigger_at` datetime(3) DEFAULT NULL COMMENT '触发时间',
  `event_content` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '事件内容',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='事件触发';

