-- ----------------------------
-- Table structure for mdo_help_doc
-- ----------------------------
DROP TABLE IF EXISTS `mdo_help_doc`;
CREATE TABLE `mdo_help_doc` (
  `id` bigint NOT NULL COMMENT 'id',
  `title` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '文档名称',
  `weight` int NOT NULL DEFAULT '0' COMMENT '排序',
  `state` bit(1) NOT NULL DEFAULT b'1' COMMENT '状态\n1：启用，0：禁用',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '内容',
  `content_type` smallint NOT NULL DEFAULT '1' COMMENT '内容类型\n1-Markdown,2-富文本',
  `parent_id` bigint DEFAULT NULL COMMENT '父级id',
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '添加时间',
  `updated_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3) COMMENT '修改时间',
  `created_by` bigint DEFAULT '0' COMMENT '创建人id',
  `updated_by` bigint DEFAULT '0' COMMENT '修改人id',
  `tree_path` varchar(1024) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '树路径',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci ROW_FORMAT=DYNAMIC COMMENT='帮助文档';

-- ----------------------------
-- Records of mdo_help_doc
-- ----------------------------
BEGIN;
INSERT INTO `mdo_help_doc` (`id`, `title`, `weight`, `state`, `content`, `content_type`, `parent_id`, `created_at`, `updated_at`, `created_by`, `updated_by`, `tree_path`) VALUES (45452754131160064, '示例1： Java基础语法入门', 1, b'1', '# 文档一：Java基础语法入门\n\n## 一、Java简介与环境搭建\n\nJava是一种跨平台、面向对象的编程语言，具有“一次编写，到处运行”的特性，广泛应用于后端开发、移动开发等领域。要开展Java开发，首先需完成环境搭建，核心是安装JDK（Java Development Kit，Java开发工具包）。\n\n### 环境搭建步骤：\n\n1. 下载JDK：前往Oracle官网（https://www.oracle.com/java/technologies/downloads/），选择对应操作系统（Windows/macOS/Linux）的JDK版本（推荐Java 8或Java 17，兼容性较好）。\n\n2. 安装JDK：双击安装包，按向导完成安装，记住安装路径（如Windows下的“C:\\Program Files\\Java\\jdk1.8.0_301”）。\n\n3. 配置环境变量：\n       \n\n    - Windows：右键“此电脑”→“属性”→“高级系统设置”→“环境变量”，在系统变量中新建“JAVA_HOME”，值为JDK安装路径；编辑“Path”变量，添加“%JAVA_HOME%\\bin”和“%JAVA_HOME%\\jre\\bin”。\n\n    - macOS/Linux：打开终端，编辑~/.bash_profile或~/.zshrc文件，添加“export JAVA_HOME=JDK安装路径”“export PATH=$JAVA_HOME/bin:$PATH”，保存后执行“source ~/.bash_profile”生效。\n\n4. 验证：打开终端，输入“java -version”和“javac -version”，若显示版本信息则说明环境搭建成功。\n\n## 二、第一个Java程序：Hello World\n\n环境搭建完成后，编写第一个Java程序，步骤如下：\n\n1. 创建源文件：新建文本文件，命名为“HelloWorld.java”（注意：文件名必须与类名一致，后缀为.java）。\n\n2. 编写代码：\n`// 定义公共类HelloWorld\npublic class HelloWorld {\n    // 程序入口方法，main方法是Java程序的执行起点\n    public static void main(String[] args) {\n        // 输出“Hello World!”到控制台\n        System.out.println(\"Hello World!\");\n    }\n}`\n\n3. 编译与运行：\n       \n\n    - 编译：打开终端，进入源文件所在目录，输入“javac HelloWorld.java”，若没有报错，会生成“HelloWorld.class”字节码文件。\n\n    - 运行：输入“java HelloWorld”，控制台将输出“Hello World!”。\n\n## 三、核心基础语法\n\n### 1. 变量与数据类型\n\nJava是强类型语言，变量必须先声明再使用，且声明时需指定数据类型。核心数据类型分为两类：\n\n- 基本数据类型（8种）：\n        \n\n    - 整数类型：byte（1字节）、short（2字节）、int（4字节，默认）、long（8字节，声明时需加L后缀，如100L）。\n\n    - 浮点类型：float（4字节，声明时需加F后缀，如3.14F）、double（8字节，默认）。\n\n    - 字符类型：char（2字节，用单引号包裹，如\'a\'、\'中\'）。\n\n    - 布尔类型：boolean（1字节，值为true或false）。\n\n- 引用数据类型：类（如String）、数组、接口等，默认值为null。\n\n变量声明示例：\n\n```java\n\npublic class VariableDemo {\n    public static void main(String[] args) {\n        // 基本数据类型变量\n        int age = 20;\n        double score = 95.5;\n        char gender = \'男\';\n        boolean isPass = true;\n        \n        // 引用数据类型变量\n        String name = \"张三\";\n        \n        // 输出变量值\n        System.out.println(\"姓名：\" + name + \"，年龄：\" + age);\n    }\n}\n```\n\n### 2. 运算符\n\n常用运算符包括：\n\n- 算术运算符：+（加）、-（减）、*（乘）、/（除）、%（取余）、++（自增）、--（自减）。\n\n- 关系运算符：==（等于）、!=（不等于）、>（大于）、<（小于）、>=（大于等于）、<=（小于等于），结果为boolean类型。\n\n- 逻辑运算符：&&（短路与）、||（短路或）、!（非），用于连接boolean表达式。\n\n- 赋值运算符：=、+=、-=、*=、/=等。\n\n### 3. 流程控制语句\n\n用于控制程序执行顺序，核心包括：\n\n- 条件语句：if-else、switch-case。\n\n- 循环语句：for、while、do-while。\n\n- 跳转语句：break（跳出循环或switch）、continue（跳过本次循环，进入下一次）。\n\n示例（for循环与if-else）：\n\n```java\n\npublic class FlowControlDemo {\n    public static void main(String[] args) {\n        // 循环输出1-10的数字，判断奇偶性\n        for (int i = 1; i <= 10; i++) {\n            if (i % 2 == 0) {\n                System.out.println(i + \"是偶数\");\n            } else {\n                System.out.println(i + \"是奇数\");\n            }\n        }\n    }\n}\n```', 1, NULL, '2026-01-15 14:10:15.843', '2026-01-15 15:36:04.017', 680083598598475778, 680083598598475778, '/45452754131160064/');
INSERT INTO `mdo_help_doc` (`id`, `title`, `weight`, `state`, `content`, `content_type`, `parent_id`, `created_at`, `updated_at`, `created_by`, `updated_by`, `tree_path`) VALUES (45452754131160065, '文档二：Java面向对象基础', 2, b'1', '# 文档二：Java面向对象基础\n\n## 一、面向对象核心概念\n\nJava是纯面向对象编程语言，核心思想是“万物皆对象”，即将现实世界中的事物抽象为程序中的“对象”，通过对象的“属性”（特征）和“方法”（行为）描述事物。面向对象有三大特性：封装、继承、多态。\n\n关键术语：\n\n- 类：对象的抽象模板，定义了对象的属性和方法，如“Person”类。\n\n- 对象：类的实例化结果，如“张三”是“Person”类的一个对象。\n\n- 属性：类中的成员变量，描述对象的特征，如Person类的name、age。\n\n- 方法：类中的成员函数，描述对象的行为，如Person类的eat()、sleep()。\n\n## 二、类与对象的创建和使用\n\n### 1. 定义类\n\n类的定义格式：\n\n```java\n\n// 定义Person类\npublic class Person {\n    // 成员变量（属性）\n    String name;\n    int age;\n    \n    // 成员方法（行为）\n    // 无参数无返回值方法\n    public void eat() {\n        System.out.println(name + \"在吃饭\");\n    }\n    \n    // 有参数有返回值方法\n    public int getAge() {\n        return age;\n    }\n}\n```\n\n### 2. 创建与使用对象\n\n通过“new”关键字创建对象，格式为：`类名 对象名 = new 类名();`，之后通过“对象名.属性”“对象名.方法()”操作对象。\n\n示例：\n\n```java\n\npublic class PersonTest {\n    public static void main(String[] args) {\n        // 创建Person对象\n        Person zhangsan = new Person();\n        \n        // 给对象的属性赋值\n        zhangsan.name = \"张三\";\n        zhangsan.age = 25;\n        \n        // 调用对象的方法\n        zhangsan.eat();\n        int age = zhangsan.getAge();\n        System.out.println(\"年龄：\" + age);\n    }\n}\n```\n\n### 3. 构造方法\n\n构造方法是类中特殊的方法，用于对象的初始化，创建对象时自动调用。其特点：\n\n- 方法名与类名完全一致。\n\n- 没有返回值类型（包括void）。\n\n- 若类中未定义构造方法，系统会默认提供一个无参构造方法；若自定义了构造方法，默认无参构造会失效。\n\n示例（带参构造方法）：\n\n```java\n\npublic class Person {\n    String name;\n    int age;\n    \n    // 无参构造方法\n    public Person() {}\n    \n    // 带参构造方法\n    public Person(String n, int a) {\n        name = n;\n        age = a;\n    }\n    \n    public void eat() {\n        System.out.println(name + \"在吃饭\");\n    }\n}\n\n// 使用带参构造创建对象\npublic class PersonTest {\n    public static void main(String[] args) {\n        Person lisi = new Person(\"李四\", 30);\n        lisi.eat(); // 输出：李四在吃饭\n    }\n}\n```\n\n## 三、面向对象三大特性\n\n### 1. 封装\n\n封装是指将对象的属性和方法隐藏起来，仅通过公共的方法对外提供访问和修改接口，目的是提高代码安全性和可维护性。实现步骤：\n\n1. 将成员变量用“private”修饰（私有访问权限，仅本类可访问）。\n\n2. 提供公共的“getter”方法（获取属性值）和“setter”方法（修改属性值）。\n\n示例：\n\n```java\n\npublic class Person {\n    // 私有成员变量\n    private String name;\n    private int age;\n    \n    // getter方法（获取name）\n    public String getName() {\n        return name;\n    }\n    \n    // setter方法（修改name）\n    public void setName(String n) {\n        // 可在setter中添加逻辑校验\n        if (n != null && !n.equals(\"\")) {\n            name = n;\n        } else {\n            System.out.println(\"姓名不能为空\");\n        }\n    }\n    \n    // getter和setter方法（age）\n    public int getAge() {\n        return age;\n    }\n    \n    public void setAge(int a) {\n        if (a > 0 && a < 150) {\n            age = a;\n        } else {\n            System.out.println(\"年龄输入无效\");\n        }\n    }\n}\n\n// 使用封装后的类\npublic class PersonTest {\n    public static void main(String[] args) {\n        Person wangwu = new Person();\n        wangwu.setName(\"王五\");\n        wangwu.setAge(28);\n        System.out.println(\"姓名：\" + wangwu.getName() + \"，年龄：\" + wangwu.getAge());\n        \n        wangwu.setAge(200); // 输出：年龄输入无效\n    }\n}\n```\n\n### 2. 继承\n\n继承是指一个类（子类）继承另一个类（父类）的属性和方法，子类可复用父类的代码，同时可添加自己的特有属性和方法，实现代码复用和扩展。Java中类只能单继承（一个子类只能有一个直接父类），通过“extends”关键字实现。\n\n示例：\n\n```java\n\n// 父类：Person\npublic class Person {\n    private String name;\n    private int age;\n    \n    // getter和setter方法\n    public String getName() { return name; }\n    public void setName(String name) { this.name = name; }\n    public int getAge() { return age; }\n    public void setAge(int age) { this.age = age; }\n    \n    public void eat() {\n        System.out.println(name + \"在吃饭\");\n    }\n}\n\n// 子类：Student，继承Person\npublic class Student extends Person {\n    // 子类特有属性\n    private String studentId;\n    \n    // 子类特有方法\n    public void study() {\n        System.out.println(getName() + \"（学号：\" + studentId + \"）在学习\");\n    }\n    \n    // 子类getter和setter方法\n    public String getStudentId() { return studentId; }\n    public void setStudentId(String studentId) { this.studentId = studentId; }\n}\n\n// 测试类\npublic class StudentTest {\n    public static void main(String[] args) {\n        Student zhaoliu = new Student();\n        zhaoliu.setName(\"赵六\");\n        zhaoliu.setAge(20);\n        zhaoliu.setStudentId(\"2024001\");\n        \n        zhaoliu.eat(); // 继承父类的方法，输出：赵六在吃饭\n        zhaoliu.study(); // 子类特有方法，输出：赵六（学号：2024001）在学习\n    }\n}\n```\n\n### 3. 多态\n\n多态是指同一方法在不同对象上有不同的实现，即“一个接口，多种实现”。实现多态的前提：\n\n- 存在继承关系（子类继承父类）。\n\n- 子类重写父类的方法（方法名、参数列表、返回值类型完全一致，父类方法不能是private）。\n\n- 父类引用指向子类对象。\n\n示例：\n\n```java\n\n// 父类：Animal\npublic class Animal {\n    public void cry() {\n        System.out.println(\"动物在叫\");\n    }\n}\n\n// 子类：Dog，重写cry方法\npublic class Dog extends Animal {\n    @Override\n    public void cry() {\n        System.out.println(\"小狗汪汪叫\");\n    }\n}\n\n// 子类：Cat，重写cry方法\npublic class Cat extends Animal {\n    @Override\n    public void cry() {\n        System.out.println(\"小猫喵喵叫\");\n    }\n}\n\n// 测试多态\npublic class AnimalTest {\n    public static void main(String[] args) {\n        // 父类引用指向子类对象\n        Animal animal1 = new Dog();\n        Animal animal2 = new Cat();\n        \n        // 调用方法时，实际执行的是子类重写后的方法\n        animal1.cry(); // 输出：小狗汪汪叫\n        animal2.cry(); // 输出：小猫喵喵叫\n    }\n}\n```\n', 1, NULL, '2026-01-15 14:10:51.081', '2026-01-15 15:36:54.214', 680083598598475778, 680083598598475778, '/45452754131160065/');
INSERT INTO `mdo_help_doc` (`id`, `title`, `weight`, `state`, `content`, `content_type`, `parent_id`, `created_at`, `updated_at`, `created_by`, `updated_by`, `tree_path`) VALUES (45452754131160066, '文档三：Java常用类与工具类入门', 3, b'1', '# 文档三：Java常用类与工具类入门\n\n## 一、String类（字符串类）\n\nString类用于表示字符串，是Java中最常用的类之一。String类是不可变类（字符串对象创建后，其内容不能被修改，修改会创建新的字符串对象）。\n\n### 1. String对象的创建\n\n```java\n\npublic class StringDemo {\n    public static void main(String[] args) {\n        // 方式1：直接赋值（推荐，会复用字符串常量池中的对象）\n        String s1 = \"Hello Java\";\n        \n        // 方式2：通过new关键字创建（会创建新对象，不复用常量池）\n        String s2 = new String(\"Hello Java\");\n        \n        // 比较两个字符串的内容（用equals方法，不要用==）\n        System.out.println(s1.equals(s2)); // 输出：true\n        \n        // 比较两个对象的地址（==）\n        System.out.println(s1 == s2); // 输出：false\n    }\n}\n```\n\n### 2. 常用方法\n\n- length()：返回字符串的长度。\n\n- equals(Object obj)：比较两个字符串的内容是否相等（区分大小写）。\n\n- equalsIgnoreCase(String anotherString)：比较两个字符串的内容是否相等（不区分大小写）。\n\n- concat(String str)：拼接字符串，等价于“+”。\n\n- substring(int beginIndex)：从指定索引开始截取字符串，直到末尾。\n\n- substring(int beginIndex, int endIndex)：从beginIndex截取到endIndex（左闭右开，不包含endIndex）。\n\n- trim()：去除字符串前后的空白字符（空格、制表符等）。\n\n- indexOf(String str)：返回指定子串在字符串中第一次出现的索引，若不存在返回-1。\n\n- replace(CharSequence target, CharSequence replacement)：替换字符串中的指定子串。\n\n示例：\n\n```java\n\npublic class StringMethodDemo {\n    public static void main(String[] args) {\n        String s = \"  Hello Java World  \";\n        \n        System.out.println(s.length()); // 输出：17\n        System.out.println(s.trim()); // 输出：Hello Java World\n        System.out.println(s.substring(2, 11)); // 输出：Hello Java\n        System.out.println(s.replace(\"Java\", \"Python\")); // 输出：  Hello Python World  \n        System.out.println(s.indexOf(\"World\")); // 输出：12\n    }\n}\n```\n\n## 二、ArrayList类（动态数组）\n\nArrayList是Java集合框架中的动态数组类，用于存储多个元素，相比普通数组（固定长度），ArrayList的长度可以动态变化，支持添加、删除、修改元素等操作。ArrayList位于java.util包下，使用前需导入。\n\n### 1. 基本使用\n\n```java\n\nimport java.util.ArrayList;\n\npublic class ArrayListDemo {\n    public static void main(String[] args) {\n        // 创建ArrayList对象，指定存储String类型的元素\n        ArrayList<String> list = new ArrayList<>();\n        \n        // 添加元素（add方法）\n        list.add(\"苹果\");\n        list.add(\"香蕉\");\n        list.add(\"橙子\");\n        System.out.println(list); // 输出：[苹果, 香蕉, 橙子]\n        \n        // 获取元素（get方法，索引从0开始）\n        String fruit = list.get(1);\n        System.out.println(fruit); // 输出：香蕉\n        \n        // 修改元素（set方法）\n        list.set(2, \"葡萄\");\n        System.out.println(list); // 输出：[苹果, 香蕉, 葡萄]\n        \n        // 删除元素（remove方法，可根据索引或元素值删除）\n        list.remove(0); // 删除索引为0的元素\n        System.out.println(list); // 输出：[香蕉, 葡萄]\n        \n        // 获取集合长度（size方法）\n        System.out.println(list.size()); // 输出：2\n        \n        // 遍历集合（for循环）\n        for (int i = 0; i < list.size(); i++) {\n            System.out.println(list.get(i));\n        }\n        \n        // 增强for循环遍历（更简洁）\n        for (String s : list) {\n            System.out.println(s);\n        }\n    }\n}\n```\n\n### 2. 注意事项\n\n- ArrayList存储的是引用数据类型，不能直接存储基本数据类型（如int、double），若需存储基本数据类型，需使用对应的包装类（Integer、Double等）。\n\n- 示例（存储整数）：\n`ArrayList<Integer> numList = new ArrayList<>();\nnumList.add(10); // 自动装箱（int→Integer）\nnumList.add(20);\nint num = numList.get(0); // 自动拆箱（Integer→int）\nSystem.out.println(num); // 输出：10`\n\n## 三、Scanner类（输入工具类）\n\nScanner类用于从控制台获取用户输入，是Java入门阶段常用的输入工具，位于java.util包下，使用前需导入。\n\n### 1. 基本使用\n\n```java\n\nimport java.util.Scanner;\n\npublic class ScannerDemo {\n    public static void main(String[] args) {\n        // 创建Scanner对象，关联控制台输入\n        Scanner scanner = new Scanner(System.in);\n        \n        // 获取字符串输入（nextLine()方法）\n        System.out.print(\"请输入姓名：\");\n        String name = scanner.nextLine();\n        \n        // 获取整数输入（nextInt()方法）\n        System.out.print(\"请输入年龄：\");\n        int age = scanner.nextInt();\n        \n        // 获取浮点数输入（nextDouble()方法）\n        System.out.print(\"请输入成绩：\");\n        double score = scanner.nextDouble();\n        \n        // 输出获取到的信息\n        System.out.println(\"姓名：\" + name + \"，年龄：\" + age + \"，成绩：\" + score);\n        \n        // 关闭Scanner（释放资源）\n        scanner.close();\n    }\n}\n```\n\n### 2. 常用方法\n\n- nextLine()：获取一行字符串（包括空格）。\n\n- next()：获取一个字符串（以空格或回车为分隔符，不包含空格）。\n\n- nextInt()：获取整数。\n\n- nextDouble()：获取浮点数。\n\n- hasNextInt()：判断下一个输入是否为整数，返回boolean类型（用于避免输入类型错误）。\n\n### 3. 注意事项\n\n使用nextInt()、nextDouble()等方法后，若后续使用nextLine()，会导致nextLine()读取到空字符串（因为前一个方法会留下回车符）。解决方法：在nextInt()后添加一行scanner.nextLine()，消耗掉回车符。\n\n```java\n\nimport java.util.Scanner;\n\npublic class ScannerNote {\n    public static void main(String[] args) {\n        Scanner scanner = new Scanner(System.in);\n        \n        System.out.print(\"请输入年龄：\");\n        int age = scanner.nextInt();\n        scanner.nextLine(); // 消耗回车符\n        \n        System.out.print(\"请输入姓名：\");\n        String name = scanner.nextLine();\n        \n        System.out.println(\"姓名：\" + name + \"，年龄：\" + age);\n        scanner.close();\n    }\n}\n```', 1, NULL, '2026-01-15 14:46:50.336', '2026-01-15 15:41:10.849', 680083598598475778, 680083598598475778, '/45452754131160066/');
COMMIT;

-- ----------------------------
-- Table structure for mdo_notify_info
-- ----------------------------
DROP TABLE IF EXISTS `mdo_notify_info`;
CREATE TABLE `mdo_notify_info` (
  `id` bigint NOT NULL COMMENT 'ID',
  `call_log_id` bigint DEFAULT NULL COMMENT '所属调用',
  `app_id` bigint NOT NULL COMMENT '所属应用',
  `app_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '应用秘钥',
  `api_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '接口名称',
  `api_version` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '接口版本',
  `notify_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '回调url',
  `request_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '请求参数',
  `last_request_time` datetime(3) DEFAULT NULL COMMENT '最后请求时间',
  `next_request_time` datetime(3) DEFAULT NULL COMMENT '下次请求时间',
  `max_request_cnt` int DEFAULT NULL COMMENT '最大请求次数',
  `request_cnt` int DEFAULT NULL COMMENT '已请求次数',
  `exec_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '执行状态\n[0-待执行 1-执行成功 2-执行失败 3-重试结束 4-手动结束]',
  `remark` varchar(256) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `created_at` datetime(3) DEFAULT CURRENT_TIMESTAMP(3) COMMENT '创建时间',
  `updated_at` datetime(3) DEFAULT CURRENT_TIMESTAMP(3) COMMENT '修改时间',
  `created_by` bigint DEFAULT '0' COMMENT '创建人id',
  `updated_by` bigint DEFAULT '0' COMMENT '修改人id',
  PRIMARY KEY (`id`),
  KEY `idx_app_id` (`app_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='回调任务';

-- ----------------------------
-- Records of mdo_notify_info
-- ----------------------------
BEGIN;
INSERT INTO `mdo_notify_info` (`id`, `call_log_id`, `app_id`, `app_key`, `api_name`, `api_version`, `notify_url`, `request_data`, `last_request_time`, `next_request_time`, `max_request_cnt`, `request_cnt`, `exec_status`, `remark`, `created_at`, `updated_at`, `created_by`, `updated_by`) VALUES (44782344095972361, 44780514439902211, 5, 'ruoyi-vue-oauth', 'org.save', '1.0', 'http://127.0.0.1:7800/anyUser/notify/callback', '{\"apiName\":\"org.save\",\"apiVersion\":\"1.0\",\"appId\":5,\"appKey\":\"ruoyi-vue-oauth\",\"bizParams\":{\"id\":44782344095972359},\"callLogId\":44780514439902211,\"charset\":\"UTF-8\",\"clientIp\":\"127.0.0.1\",\"remark\":\"新增组织回调\"}', '2026-01-14 23:43:08.749', '2026-01-13 17:20:00.000', 5, 6, '1', '新增组织回调', '2026-01-13 16:26:13.589', '2026-01-13 16:26:13.589', 0, 0);
COMMIT;

-- ----------------------------
-- Table structure for mdo_notify_info_log
-- ----------------------------
DROP TABLE IF EXISTS `mdo_notify_info_log`;
CREATE TABLE `mdo_notify_info_log` (
  `id` bigint NOT NULL COMMENT '主键',
  `notify_info_id` bigint NOT NULL COMMENT '所属推送',
  `request_time` datetime(3) DEFAULT NULL COMMENT '请求时间',
  `request_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '请求参数',
  `response_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '响应内容',
  `response_time` datetime(3) DEFAULT NULL COMMENT '响应时间',
  `exec_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '状态\n[1-执行成功 2-执行失败]',
  `error_msg` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '失败原因',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='回调任务日志';

-- ----------------------------
-- Records of mdo_notify_info_log
