-- ----------------------------
-- Table structure for mdo_oauth_log
-- ----------------------------
DROP TABLE IF EXISTS `mdo_oauth_log`;
CREATE TABLE `mdo_oauth_log` (
  `id` bigint NOT NULL COMMENT 'ID',
  `app_id` bigint DEFAULT NULL COMMENT '所属应用',
  `user_id` bigint DEFAULT NULL COMMENT '所属用户',
  `openid` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '开放id',
  `unionid` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '联合id',
  `access_token` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0' COMMENT '本次授权的token',
  `access_token_expires` datetime(3) DEFAULT NULL COMMENT '到期时间',
  `refresh_token` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '本次授权的刷新token',
  `refresh_token_expires` datetime(3) DEFAULT NULL COMMENT '刷新token到期时间',
  `grant_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '授权类型',
  `scopes` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '授权范围',
  `token_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '类型',
  `remarks` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `redirect_uri` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '授权地址',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='授权记录';

